mapper.select:
SELECT COALESCE(point, 0)
FROM member
WHERE member_no = #{memberNo}

mapper.update:
UPDATE product
SET stock = stock - #{quantity}
WHERE product_no = #{productNo}
AND stock >= #{quantity}

UPDATE member
SET point = point - #{usedPoint}
WHERE member_no = #{memberNo}
AND point >= #{usedPoint}

UPDATE member
SET point = point + #{pointSave}
WHERE member_no = #{memberNo}
